          boxShadow: isDark ? "0 2px 12px rgba(124,58,237,0.4)" : "0 2px 12px rgba(124,58,237,0.25)"
        }}>🤖</div>
      )}
      <div style={{ maxWidth: "76%" }}>
        <div style={{
          background: isUser
            ? "linear-gradient(135deg, #7c3aed, #a78bfa)"
            : isDark ? "rgba(255,255,255,0.06)" : "rgba(0,0,0,0.04)",
